-- Create "account_availability_rollups" table
CREATE TABLE "account_availability_rollups" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "account_id" bigint NOT NULL,
  "provider_id" bigint NOT NULL DEFAULT 0,
  "bucket_date" character varying NOT NULL,
  "total_samples" bigint NOT NULL DEFAULT 0,
  "healthy_samples" bigint NOT NULL DEFAULT 0,
  "availability_ratio" double precision NOT NULL DEFAULT 0,
  "avg_success_rate" double precision NOT NULL DEFAULT 0,
  "computed_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "accountavailabilityrollup_account_id" to table: "account_availability_rollups"
CREATE INDEX "accountavailabilityrollup_account_id" ON "account_availability_rollups" ("account_id");
-- Create index "accountavailabilityrollup_account_id_bucket_date" to table: "account_availability_rollups"
CREATE UNIQUE INDEX "accountavailabilityrollup_account_id_bucket_date" ON "account_availability_rollups" ("account_id", "bucket_date");
-- Create "error_passthrough_rules" table
CREATE TABLE "error_passthrough_rules" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "enabled" boolean NOT NULL DEFAULT true,
  "priority" bigint NOT NULL DEFAULT 0,
  "action" character varying NOT NULL DEFAULT 'expose',
  "match_status_codes" jsonb NULL,
  "match_classes" jsonb NULL,
  "match_keywords" jsonb NULL,
  PRIMARY KEY ("id")
);
-- Create index "errorpassthroughrule_enabled_priority" to table: "error_passthrough_rules"
CREATE INDEX "errorpassthroughrule_enabled_priority" ON "error_passthrough_rules" ("enabled", "priority");
-- Create "tls_fingerprint_profiles" table
CREATE TABLE "tls_fingerprint_profiles" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "tls_template" character varying NOT NULL DEFAULT '',
  "http_version_policy" character varying NOT NULL DEFAULT 'prefer_h2',
  "user_agent" character varying NOT NULL DEFAULT '',
  "extra_headers" jsonb NULL,
  "enabled" boolean NOT NULL DEFAULT true,
  PRIMARY KEY ("id")
);
-- Create index "tlsfingerprintprofile_enabled" to table: "tls_fingerprint_profiles"
CREATE INDEX "tlsfingerprintprofile_enabled" ON "tls_fingerprint_profiles" ("enabled");
-- Create index "tlsfingerprintprofile_name" to table: "tls_fingerprint_profiles"
CREATE UNIQUE INDEX "tlsfingerprintprofile_name" ON "tls_fingerprint_profiles" ("name");
-- Create "user_attribute_definitions" table
CREATE TABLE "user_attribute_definitions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "key" character varying NOT NULL,
  "name" character varying NOT NULL,
  "data_type" character varying NOT NULL DEFAULT 'string',
  "options_json" jsonb NULL,
  "required" boolean NOT NULL DEFAULT false,
  "display_order" bigint NOT NULL DEFAULT 0,
  "enabled" boolean NOT NULL DEFAULT true,
  PRIMARY KEY ("id")
);
-- Create index "userattributedefinition_enabled_display_order" to table: "user_attribute_definitions"
CREATE INDEX "userattributedefinition_enabled_display_order" ON "user_attribute_definitions" ("enabled", "display_order");
-- Create index "userattributedefinition_key" to table: "user_attribute_definitions"
CREATE UNIQUE INDEX "userattributedefinition_key" ON "user_attribute_definitions" ("key");
-- Create "user_attribute_values" table
CREATE TABLE "user_attribute_values" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "definition_id" bigint NOT NULL,
  "value" character varying NOT NULL DEFAULT '',
  PRIMARY KEY ("id")
);
-- Create index "userattributevalue_definition_id" to table: "user_attribute_values"
CREATE INDEX "userattributevalue_definition_id" ON "user_attribute_values" ("definition_id");
-- Create index "userattributevalue_user_id_definition_id" to table: "user_attribute_values"
CREATE UNIQUE INDEX "userattributevalue_user_id_definition_id" ON "user_attribute_values" ("user_id", "definition_id");
